diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 1ba548b6ff06..28d6328300a7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1153,11 +1153,13 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {
 // does not overflow.
 // Simplifies (X / C0) * C1 + (X % C0) * C2 to
 // (X / C0) * (C1 - C2 * C0) + X * C2
+
 Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
   APInt C0, MulOpC;
   bool IsSigned;
+  
   // Match I = X % C0 + MulOpV * C0
   if (((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
        (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) &&
@@ -1193,16 +1195,60 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   }
   Value *DivOpV;
   APInt DivOpC;
-  if (MatchRem(Rem, X, C0, IsSigned) &&
-      MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
+  
+  // Try to match Div as either X/C0 or X>>log2(C0) where C0 is power of two
+  auto MatchDivOrShift = [&](Value *V, Value *&X, APInt &C, bool &IsSigned) -> bool {
+    if (MatchDiv(V, X, C, IsSigned))
+      return true;
+    
+    // Try to match lshr as unsigned division by power-of-two
+    const APInt *ShiftAmt;
+    if (match(V, m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
+      if (ShiftAmt->isPowerOf2()) {
+        C = APInt(ShiftAmt->getBitWidth(), 1) << ShiftAmt->getZExtValue();
+        IsSigned = false;
+        return true;
+      }
+    }
+    return false;
+  };
+  
+  // Try to match Rem as either X%C0 or X&(C0-1) where C0 is power of two
+  auto MatchRemOrMask = [&](Value *V, Value *&X, APInt &C, bool &IsSigned) -> bool {
+    if (MatchRem(V, X, C, IsSigned))
+      return true;
+    
+    // Try to match and as unsigned remainder
+    const APInt *Mask;
+    if (match(V, m_And(m_Value(X), m_APInt(Mask)))) {
+      // Check if Mask+1 is power of two
+      APInt CTest = *Mask + 1;
+      if (CTest.isPowerOf2()) {
+        C = CTest;
+        IsSigned = false;
+        return true;
+      }
+    }
+    return false;
+  };
+  
+  if (MatchRemOrMask(Rem, X, C0, IsSigned) &&
+      MatchDivOrShift(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
     APInt NewC = C1 - C2 * C0;
-    if (!NewC.isZero() && !Rem->hasOneUse())
+    
+    // Only apply the hasOneUse restriction if we're not in the simple case
+    // where both coefficients are 1 (original pattern without multiplications)
+    bool SimpleCase = (C1 == 1 && C2 == 1);
+    if (!NewC.isZero() && !Rem->hasOneUse() && !SimpleCase)
       return nullptr;
+      
     if (!isGuaranteedNotToBeUndef(X, &AC, &I, &DT))
       return nullptr;
+      
     Value *MulXC2 = Builder.CreateMul(X, ConstantInt::get(X->getType(), C2));
     if (NewC.isZero())
       return MulXC2;
+      
     return Builder.CreateAdd(
         Builder.CreateMul(Div, ConstantInt::get(X->getType(), NewC)), MulXC2);
   }
@@ -1210,6 +1256,7 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   return nullptr;
 }

+
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:
